import sqlite3
from typing import Dict, Union

def get_order(user_id: int, order_id: str) -> Union[Dict[str, str], None]:
    conn = sqlite3.connect('mydatabase.db')  # Connect to the database (replace 'mydatabase' with your actual db name).
    
    cursor = conn.cursor()  
      
    query="SELECT * FROM orders WHERE user_id=? AND order_id=?";     
        
    result = cursor.execute(query, (user_id ,order_id))  # Execute the SQL command and fetch data from database using ? placeholders for parameters in execute function call .  
    
    row =  result.fetchone()       # Fetch one record at a time while iterating over all records with 'row' variable, if you want to get specific column use cursor.execute(query,...)  and specify the columns instead of using fetchall(). If no data found then it will return None
    
    conn.close();   # Close connection after fetching is done . It’s a good practice as not closing connections can cause issues in multi-threaded environments or when working with large datasets where you may end up consuming too much memory for the database server to handle requests concurrently, and it'll be better if we close our resources.
    
    return row  # Returning None means no data found . If any order is present then a dictionary will contain user_id ,order_id & other details of that particular record in orders table as per requirement else none or empty dict can also returned based on your requirements and business logic.